import React from 'react';
import { Link, Outlet } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

/**
 * Defines available modules and their metadata.
 * - key: permission key used in backend
 * - label: human readable label
 * - path: internal React route (if implemented) or null if not yet migrated
 * - fallback: external URL within the Flask app to open in a new tab for legacy pages
 */
const modules = [
  { key: 'etiquetas', label: 'Etiquetas', path: '/etiquetas', implemented: true, fallback: '/_legacy/etiquetas/' },
  { key: 'rastreo_deposito', label: 'Rastreo', path: '/rastreo', implemented: false, fallback: '/rastreo/deposito' },
  { key: 'cfe_manual', label: 'CFE Manual', path: null, implemented: false, fallback: '/_legacy/cfe_manual/' },
  { key: 'cfe_auto', label: 'CFE Auto', path: null, implemented: false, fallback: '/_legacy/cfe_auto/' },
  { key: 'batch_pedidos', label: 'Batch Pedidos', path: null, implemented: false, fallback: '/batch-pedidos' },
  { key: 'cadete_flex', label: 'Cadete Flex', path: null, implemented: false, fallback: '/cadete-flex' },
  { key: 'rastreo_ventas', label: 'Tracking Admin', path: null, implemented: false, fallback: '/rastreo/ventas' },
  { key: 'admin_postulaciones', label: 'Postulaciones', path: null, implemented: false, fallback: '/postulaciones/admin' },
  { key: 'puerta', label: 'Puerta', path: null, implemented: false, fallback: '/puerta' },
  { key: 'reloj_home_office', label: 'Reloj Home', path: null, implemented: false, fallback: '/reloj-home-office' },
];

/**
 * Layout component that renders a simple header, side navigation and outlet for pages.
 * It uses permissions from the AuthContext to build the navigation dynamically.
 */
const Layout = () => {
  const { user, permissions, logout } = useAuth();

  const handleLogout = async () => {
    await logout();
    // Recargar completamente para limpiar estado e ir a login
    window.location.href = '/login';
  };

  return (
    <div>
      <header style={{ padding: '10px', backgroundColor: '#f5f5f5', borderBottom: '1px solid #ddd' }}>
        <span style={{ marginRight: '20px' }}>
          {user ? `Usuario: ${user.username}` : 'No autenticado'}
        </span>
        <button onClick={handleLogout}>Salir</button>
      </header>
      <div style={{ display: 'flex' }}>
        <nav style={{ width: '220px', borderRight: '1px solid #ddd', padding: '10px' }}>
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {modules.map((m) => {
              if (!permissions.includes(m.key)) return null;
              if (m.implemented && m.path) {
                return (
                  <li key={m.key} style={{ marginBottom: '8px' }}>
                    <Link to={m.path}>{m.label}</Link>
                  </li>
                );
              }
              // Fallback: open legacy page in new tab
              return (
                <li key={m.key} style={{ marginBottom: '8px' }}>
                  <a
                    href={`http://localhost:5914${m.fallback}`}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    {m.label} (legacy)
                  </a>
                </li>
              );
            })}
          </ul>
        </nav>
        <main style={{ flex: 1, padding: '10px' }}>
          <Outlet />
        </main>
      </div>
    </div>
  );
};

export default Layout;
